/* ============ RENDER CARDS ============ */
function card(item, isService){
  if(isService){
    return `<a class="svc" href="${item.url}" target="_blank" rel="noopener">
      <div class="ic">${item.e}</div>
      <div class="info"><h4>${item.t}</h4><p>${item.d}</p></div>
      <div class="arrow">طلب الخدمة ←</div>
    </a>`;
  }
  const soon = item.tag === 'قريبًا';
  const isPremium = item.free === false || (item.badge && item.badge.includes('مميّز'));
  
  const sess = typeof localStorage !== 'undefined' ? localStorage.getItem(SESS) : null;
  const role = typeof localStorage !== 'undefined' ? localStorage.getItem('sac_role') : null;
  const isAdminMode = typeof window !== 'undefined' && (window.location.search.includes('admin=1') || role === 'admin' || sess === 'admin@sac-svt.dz' || sess === 'admin');
  const isUserMode = Boolean(sess || isAdminMode);

  let lockBadge = '';
  let cls = 'card';
  let goText = item.link ? 'افتح ←' : 'تصفّح';
  let tagColor = ' style="background:#e0f2fe;color:#0369a1"';

  if(isPremium){
    if(isAdminMode){
      cls = 'card';
      lockBadge = `<span class="lock-badge" style="background:#fef3c7; color:#92400e; border:1px solid #f59e0b; padding:4px 10px; border-radius:8px; font-weight:800; font-size:0.82rem; display:inline-block; margin-bottom:8px;">👑 مفتوح للأدمين (صلاحية كاملة)</span>`;
      goText = '👑 تصفّح / تحميل مباشر ←';
      tagColor = ' style="background:#fef3c7;color:#92400e"';
    } else if(isUserMode){
      cls = 'card';
      lockBadge = `<span class="lock-badge" style="background:#dcfce7; color:#166534; border:1px solid #22c55e; padding:4px 10px; border-radius:8px; font-weight:800; font-size:0.82rem; display:inline-block; margin-bottom:8px;">🔓 مفتوح لك (أستاذ مسجّل)</span>`;
      goText = '🔓 تصفّح / تحميل المورد ←';
      tagColor = ' style="background:#dcfce7;color:#166534"';
    } else {
      cls = 'card premium';
      lockBadge = `<span class="lock-badge">🔒 مميّز (يتطلب دخول)</span>`;
      goText = '🔒 افتح (مميّز)';
      tagColor = ' style="background:#fde9d6;color:#b46a1e"';
    }
  } else {
    lockBadge = `<span class="lock-badge" style="background:#f0fdf4; color:#15803d; border:1px solid #bbf7d0; padding:3px 8px; border-radius:6px; font-weight:700; font-size:0.8rem; display:inline-block; margin-bottom:8px;">🆓 مجاني للجميع</span>`;
  }

  const inner = `
    ${item.tag ? `<span class="tag"${tagColor}>${item.tag}</span>` : ""}
    ${lockBadge}
    <div class="emoji">${item.e || '📑'}</div>
    <h3>${item.t}</h3>
    <p>${item.d}</p>
    <span class="go" style="${isUserMode && isPremium ? 'color:#0d9488;font-weight:800' : ''}">${goText}</span>`;

  if(item.link){
    if(isPremium && !isUserMode && !isAdminMode){
      return `<a class="${cls}" href="javascript:void(0)" onclick="guardPremium('${item.link}')" style="text-decoration:none">${inner}</a>`;
    }
    return `<a class="${cls}" href="${item.link}" style="text-decoration:none">${inner}</a>`;
  }
  return `<div class="${cls}"${soon?' style="opacity:.72"':''}>${inner}</div>`;
}

function renderAllGridsNow(){
  const cGrid = document.getElementById('contentsGrid'); if(cGrid) cGrid.innerHTML = contents.map(c=>card(c)).join('');
  const lGrid = document.getElementById('libraryGrid');  if(lGrid) lGrid.innerHTML  = library.map(c=>card(c)).join('');
  const sGrid = document.getElementById('svtGrid');       if(sGrid) sGrid.innerHTML       = svt.map(c=>card(c)).join('');
  const vGrid = document.getElementById('servicesGrid'); if(vGrid) vGrid.innerHTML = services.map(c=>card(c,true)).join('');
  const fGrid = document.getElementById('freeGrid');
  if(fGrid){
    const freeItems = [...contents, ...library, ...svt].filter(i => i.free === true);
    fGrid.innerHTML = freeItems.map(c=>card(c)).join('');
  }
}

/* 🔒 بوّابة المحتوى المميّز */
function guardPremium(link){
  const sess = localStorage.getItem(SESS);
  const role = localStorage.getItem('sac_role');
  const users = getUsers();
  if(window.location.search.includes('admin=1') || role === 'admin' || (sess && (users[sess] || sess === 'admin@sac-svt.dz' || sess === 'admin'))){
    window.location.href = link;
  } else {
    sessionStorage.setItem('sac_redirect', link);
    openLogin('user');
  }
}

/* ============ SEARCH ============ */
const searchIndex = [...contents, ...library, ...svt, ...services.map(s=>({...s,d:s.d+" (خدمة)"}))];
function doSearch(q){
  q = q.trim().toLowerCase();
  const rs = document.getElementById('searchResults');
  const grid = document.getElementById('resultsGrid');
  const none = document.getElementById('noResults');
  if(!q){ rs.style.display='none'; return; }
  rs.style.display='block';
  const hits = searchIndex.filter(i=>(i.t+i.d).toLowerCase().includes(q));
  grid.innerHTML = hits.map(c=>card(c)).join('');
  none.style.display = hits.length? 'none':'block';
  rs.scrollIntoView({behavior:'smooth'});
}

