/* ============ COMMENTS (Supabase + Local Export) ============ */
let commentsSb = null;

async function initComments(){
  try{
    if(window.supabase) commentsSb = window.supabase.createClient(SUPABASE_URL, SUPABASE_KEY);
  }catch(e){}
  await loadComments();
}

async function loadComments(){
  const list = document.getElementById('commentsList'); if(!list) return;
  let data = null;

  if(commentsSb){
    try{
      const res = await commentsSb.from('comments').select('*').order('created_at', { ascending: false }).limit(50);
      if(!res.error && res.data) data = res.data;
    }catch(e){}
  }

  if(!data || data.length === 0){
    let localComments = [];
    try{ localComments = JSON.parse(localStorage.getItem('sac_local_comments')) || []; }catch(e){}
    if(!localComments.length){
      localComments = [
        { id: 2, name: 'زائر', text: 'شكرا لكي', time: '2025/09/08 · 14:37' },
        { id: 4, name: 'أنفال', text: 'بارك الله فيك', time: '2025/09/08 · 14:46' },
        { id: 7, name: 'شرقي شوبيلة. محبة الرحمن', text: 'بارك الله فيكم، وجزاكم الله خيرا. استاذة علوم طبيعية متوسط', time: '2025/09/09 · 05:54' },
        { id: 11, name: 'Amoulla', text: ',بارك الله فيك', time: '2025/09/10 · 01:14' },
        { id: 12, name: 'سهام بوياص', text: 'عمل جمييل في ميزان حسناتكم', time: '2025/09/11 · 07:32' }
      ];
      localStorage.setItem('sac_local_comments', JSON.stringify(localComments));
    }
    list.innerHTML = localComments.map(c => `
      <div class="comment-card">
        <div class="c-header">
          <div class="c-avatar">${c.name.charAt(0).toUpperCase()}</div>
          <div class="c-name">${escapeHtml(c.name)}</div>
          <div class="c-date">${c.time || ''}</div>
        </div>
        <div class="c-text">${escapeHtml(c.text || c.comment || '')}</div>
      </div>
    `).join('');
    return;
  }

  let repliesByComment = {};
  if(commentsSb){
    try{
      const commentIds = data.map(c => c.id);
      const { data: replies } = await commentsSb.from('replies').select('*').in('comment_id', commentIds).order('created_at', { ascending: true });
      if(replies){
        replies.forEach(r => {
          if(!repliesByComment[r.comment_id]) repliesByComment[r.comment_id] = [];
          repliesByComment[r.comment_id].push(r);
        });
      }
    }catch(e){}
  }

  list.innerHTML = data.map(c => {
    const initial = (c.name || 'زائر').charAt(0).toUpperCase();
    const date = c.created_at ? new Date(c.created_at).toLocaleDateString('ar-DZ', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }) : '';
    const commentReplies = repliesByComment[c.id] || [];
    const repliesHtml = commentReplies.map(r => `
      <div class="reply-card">
        <div class="c-header">
          <div class="c-avatar" style="background:#0369a1">${(r.name||'أدمين').charAt(0).toUpperCase()}</div>
          <div class="c-name">${escapeHtml(r.name)}</div>
          <div class="c-date">${r.created_at ? new Date(r.created_at).toLocaleDateString('ar-DZ') : ''}</div>
        </div>
        <div class="c-text">${escapeHtml(r.reply_text)}</div>
      </div>
    `).join('');

    return `
      <div class="comment-card">
        <div class="c-header">
          <div class="c-avatar">${initial}</div>
          <div class="c-name">${escapeHtml(c.name || 'زائر')}</div>
          <div class="c-date">${date}</div>
        </div>
        <div class="c-text">${escapeHtml(c.comment || c.content || '')}</div>
        ${repliesHtml}
      </div>
    `;
  }).join('');
}

async function submitComment(){
  const name = document.getElementById('commentName').value.trim() || 'أستاذ زائر';
  const text = document.getElementById('commentText').value.trim();
  const msg = document.getElementById('commentMsg');

  if(!text){
    msg.textContent = 'الرجاء كتابة نص التعليق أولاً';
    msg.className = 'msg err';
    return;
  }

  if(commentsSb){
    try{
      const { error } = await commentsSb.from('comments').insert([{ name: name, comment: text }]);
      if(!error){
        msg.textContent = '✓ تم إرسال تعليقك بنجاح ونشره في المنصة';
        msg.className = 'msg ok';
        document.getElementById('commentText').value = '';
        setTimeout(() => { loadComments(); msg.textContent = ''; }, 1200);
        return;
      }
    }catch(e){}
  }

  let localComments = [];
  try{ localComments = JSON.parse(localStorage.getItem('sac_local_comments')) || []; }catch(e){}
  localComments.unshift({ id: Date.now(), name: name, text: text, time: new Date().toLocaleString('ar-DZ') });
  localStorage.setItem('sac_local_comments', JSON.stringify(localComments));
  msg.textContent = '✓ تم إضافة تعليقك بنجاح في المنصة';
  msg.className = 'msg ok';
  document.getElementById('commentText').value = '';
  setTimeout(() => { loadComments(); msg.textContent = ''; }, 1200);
}

function escapeHtml(text){
  if(!text) return '';
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

/* ============ PAGE LOAD INIT ============ */
(function(){
  renderAllGridsNow();
  initComments();
  const sess = localStorage.getItem(SESS);
  const role = localStorage.getItem('sac_role');
  const u = getUsers();
  if(window.location.search.includes('admin=1') || role === 'admin' || sess === 'admin@sac-svt.dz' || sess === 'admin'){
    if(!sess) localStorage.setItem(SESS, 'admin@sac-svt.dz');
    localStorage.setItem('sac_role', 'admin');
    enterAdminPlatform();
  } else if(sess && u[sess]){
    enterUserPlatform(u[sess].name || sess);
  }
})();

